CREATE TYPE report_reason AS ENUM ('sexual_content','harassment','hate_or_threats','minor_safety','spam_or_scam','self_harm','other');
CREATE TYPE report_state AS ENUM ('submitted','triaged','closed');
CREATE TYPE moderation_case_state AS ENUM ('open','reviewing','resolved');
CREATE TYPE moderation_case_priority AS ENUM ('standard','high','urgent');
CREATE TYPE admin_role AS ENUM ('support','moderator','admin','superadmin');
CREATE TYPE sanction_type AS ENUM ('warning','matching_restriction','contact_restriction','temporary_suspension','full_ban','profile_removal','verification_challenge');
CREATE TYPE sanction_state AS ENUM ('active','expired','reversed');
CREATE TYPE appeal_state AS ENUM ('submitted','reviewing','upheld','granted');

CREATE TABLE reports (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), reporter_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, subject_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, encounter_id uuid REFERENCES encounters(id) ON DELETE SET NULL, call_id uuid REFERENCES calls(id) ON DELETE SET NULL, message_id uuid REFERENCES messages(id) ON DELETE SET NULL, reason report_reason NOT NULL, note text, state report_state NOT NULL DEFAULT 'submitted', client_request_id text NOT NULL, flagged_as_spam boolean NOT NULL DEFAULT false, retention_until timestamptz NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT reports_not_self CHECK (reporter_id <> subject_id), CONSTRAINT reports_note_length CHECK (note IS NULL OR char_length(note) <= 1000), CONSTRAINT reports_has_context CHECK (num_nonnulls(encounter_id,call_id,message_id)>=1));
CREATE UNIQUE INDEX reports_reporter_request_uidx ON reports(reporter_id,client_request_id);
CREATE INDEX reports_reporter_created_idx ON reports(reporter_id,created_at);
CREATE TABLE moderation_cases (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), report_id uuid NOT NULL UNIQUE REFERENCES reports(id) ON DELETE RESTRICT, subject_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, state moderation_case_state NOT NULL DEFAULT 'open', priority moderation_case_priority NOT NULL DEFAULT 'standard', assigned_to uuid REFERENCES users(id) ON DELETE SET NULL, retention_until timestamptz NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
ALTER TABLE report_evidence ADD COLUMN report_id uuid REFERENCES reports(id) ON DELETE CASCADE;
CREATE TABLE admin_roles (user_id uuid PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE, role admin_role NOT NULL, granted_by uuid REFERENCES users(id) ON DELETE RESTRICT, granted_at timestamptz NOT NULL DEFAULT now(), revoked_at timestamptz);
CREATE TABLE admin_audit_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), actor_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, action text NOT NULL, target_type text NOT NULL, target_id uuid NOT NULL, purpose text NOT NULL, case_id uuid REFERENCES moderation_cases(id) ON DELETE RESTRICT, result text NOT NULL, change_summary jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX admin_audit_actor_idx ON admin_audit_logs(actor_id,created_at);
CREATE OR REPLACE FUNCTION reject_admin_audit_mutation() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN RAISE EXCEPTION 'admin audit logs are append-only'; END $$;
CREATE TRIGGER admin_audit_no_update_delete BEFORE UPDATE OR DELETE ON admin_audit_logs FOR EACH ROW EXECUTE FUNCTION reject_admin_audit_mutation();
CREATE TABLE moderation_actions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), case_id uuid NOT NULL REFERENCES moderation_cases(id) ON DELETE RESTRICT, actor_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, action text NOT NULL, summary jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE OR REPLACE FUNCTION reject_moderation_action_mutation() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN RAISE EXCEPTION 'moderation actions are append-only'; END $$;
CREATE TRIGGER moderation_actions_no_update_delete BEFORE UPDATE OR DELETE ON moderation_actions FOR EACH ROW EXECUTE FUNCTION reject_moderation_action_mutation();
CREATE TABLE sanctions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), subject_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, case_id uuid NOT NULL REFERENCES moderation_cases(id) ON DELETE RESTRICT, type sanction_type NOT NULL, starts_at timestamptz NOT NULL DEFAULT now(), ends_at timestamptz, permanent boolean NOT NULL DEFAULT false, reason text NOT NULL, evidence_references jsonb NOT NULL DEFAULT '[]'::jsonb, actor_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, state sanction_state NOT NULL DEFAULT 'active', reversed_by uuid REFERENCES users(id) ON DELETE RESTRICT, reversed_at timestamptz, reversal_reason text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT sanctions_duration CHECK ((permanent AND ends_at IS NULL) OR NOT permanent));
CREATE INDEX sanctions_active_subject_idx ON sanctions(subject_id,state,ends_at);
CREATE TABLE appeals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), sanction_id uuid NOT NULL REFERENCES sanctions(id) ON DELETE RESTRICT, appellant_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, statement text NOT NULL, state appeal_state NOT NULL DEFAULT 'submitted', reviewer_id uuid REFERENCES users(id) ON DELETE RESTRICT, decision_reason text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT appeals_statement_length CHECK (char_length(statement) BETWEEN 20 AND 2000), UNIQUE(sanction_id,appellant_id));
